add_action('init', 'custom_auth_register_handler');
function custom_auth_register_handler() {
    if (isset($_POST['car_register_submit'])) {
        global $wpdb;
        $table_name = $wpdb->prefix . 'custom_users';
        $username = sanitize_user($_POST['car_user_login']);
        $email = sanitize_email($_POST['car_user_email']);
        $password = $_POST['car_user_pass'];

        $user_exists = $wpdb->get_var($wpdb->prepare("SELECT id FROM $table_name WHERE user_login = %s OR user_email = %s", $username, $email));
        if (!$user_exists) {
            $hashed_password = password_hash($password, PASSWORD_DEFAULT);
            $wpdb->insert(
                $table_name,
                array(
                    'user_login' => $username,
                    'user_password' => $hashed_password,
                    'user_email' => $email
                ),
                array('%s','%s','%s')
            );
        }
    }
}

