add_action('init', 'custom_auth_login_handler');
function custom_auth_login_handler() {
    if (isset($_POST['cal_login_submit'])) {
        global $wpdb;
        $table_name = $wpdb->prefix . 'custom_users';
        $username = sanitize_user($_POST['cal_user_login']);
        $password = $_POST['cal_user_pass'];
        $user = $wpdb->get_row($wpdb->prepare("SELECT * FROM $table_name WHERE user_login = %s", $username));

        if ($user && password_verify($password, $user->user_password)) {
            wp_set_current_user($user->id);
            wp_set_auth_cookie($user->id);
            do_action('wp_login', $username);
        }
    }
